@@ -1986,3 +1986,79 @@ starlight-tabs [role="tabpanel"] {
   border-color: var(--tnz-neutral-300);
   color: var(--tnz-neutral-500);
 }
+
+/* Inline icons with tooltip */
+.inline-icon-wrapper {
+  position: relative;
+  display: inline-flex;
+  align-items: center;
+  margin-right: var(--tnz-space-1);
+}
+
+.inline-icon-wrapper::after {
+  content: attr(data-tooltip);
+  position: absolute;
+  left: 50%;
+  bottom: 100%;
+  transform: translateX(-50%);
+  padding: 2px 6px;
+  background: var(--tnz-neutral-800);
+  color: var(--tnz-neutral-400);
+  font-size: 10px;
+  border-radius: 3px;
+  white-space: nowrap;
+  opacity: 0;
+  pointer-events: none;
+  transition: opacity 0.15s;
+  margin-bottom: 2px;
+}
+
+.inline-icon-wrapper:hover::after {
+  opacity: 1;
+}
+
+:root[data-theme="light"] .inline-icon-wrapper::after {
+  background: var(--tnz-neutral-200);
+  color: var(--tnz-neutral-500);
+}
+
+.inline-icon {
+  display: inline;
+  vertical-align: middle;
+  opacity: 0.4;
+  position: relative;
+  top: 1px;
+}
+
+:root[data-theme="light"] .inline-icon {
+  opacity: 0.5;
+}
+
+.fn-icon {
+  font-family: var(--tnz-font-mono);
+  font-size: 12px;
+  font-weight: 700;
+  top: 3px;
+}
+
+.op-icon {
+  top: 3px;
+}
+
+/* Icon list - icons replace bullets (auto-detected via :has) */
+ul:has(> li > .inline-icon-wrapper) {
+  list-style: none;
+  padding-left: 0;
+}
+
+ul:has(> li > .inline-icon-wrapper) > li {
+  position: relative;
+  padding-left: 1.5em;
+  line-height: 1.75;
+}
+
+ul:has(> li > .inline-icon-wrapper) .inline-icon-wrapper {
+  position: absolute;
+  left: 0;
+  top: 0.35em;
+}

