+import FnIcon from '../icons/FnIcon.astro';
+
+const name = Astro.slots.has('default')
+  ? (await Astro.slots.render('default')).trim()
+  : '';
+// Replace :: with / for namespaced functions (e.g., ocsf::category_name -> ocsf/category_name)
+const path = name.replace(/::/g, '/');
+const href = `/reference/functions/${path}`;
+---
+
+<span class="inline-icon-wrapper" data-tooltip="Function"><FnIcon class="inline-icon" /></span><a href={href}><code>{name}</code></a>

